def first_unique(text: str) -> str | None:
    """
    Returns the first character in `text` that occurs exactly once.
    If no such character exists, returns None.
    """
    # Count frequencies of each character
    freq = {}
    for char in text:
        freq[char] = freq.get(char, 0) + 1

    # Find the first character with frequency 1
    for char in text:
        if freq[char] == 1:
            return char

    return None
